                      <div className="flex-grow min-w-0 pr-2">
                          <div className="flex items-center justify-between gap-1 mb-0.5">
                              <h3 className="font-bold text-base text-gray-800 truncate leading-tight" title={detailOrder.customerName}>{detailOrder.customerName}</h3>
                              <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded flex-shrink-0 ${detailOrder.status === OrderStatus.DELIVERED ? 'bg-green-100 text-green-700' : detailOrder.status === OrderStatus.CANCELLED ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'}`}>
                                  {statusLabels[detailOrder.status]}
                              </span>
                          </div>
