                      {/* Workflow Stepper */}
                      <div className="flex bg-white rounded-lg p-1 shadow-sm border border-gray-100 mb-2">
                          <button onClick={() => handleDetailAction.setStatus(OrderStatus.PICKED_UP)} className={`flex-1 py-1.5 rounded text-[10px] font-bold transition-all ${detailOrder.status === OrderStatus.PICKED_UP ? 'bg-blue-100 text-blue-700' : 'text-gray-400 hover:bg-gray-50'}`}>Đã Lấy</button>
                          <div className="w-px bg-gray-100 mx-1"></div>
                          <button onClick={() => handleDetailAction.setStatus(OrderStatus.IN_TRANSIT)} className={`flex-1 py-1.5 rounded text-[10px] font-bold transition-all ${detailOrder.status === OrderStatus.IN_TRANSIT ? 'bg-purple-100 text-purple-700' : 'text-gray-400 hover:bg-gray-50'}`}>Đang Giao</button>
                          <div className="w-px bg-gray-100 mx-1"></div>
                          <button onClick={() => handleDetailAction.setStatus(OrderStatus.DELIVERED)} className={`flex-1 py-1.5 rounded text-[10px] font-bold transition-all ${detailOrder.status === OrderStatus.DELIVERED ? 'bg-green-100 text-green-700' : 'text-gray-400 hover:bg-gray-50'}`}>Hoàn Tất</button>
                      </div>

                      {/* Action Grid (Apps Style) */}
                      <div className="grid grid-cols-4 gap-2">
                          <button onClick={handleDetailAction.call} className="flex flex-col items-center justify-center p-2 rounded-xl bg-green-100 hover:bg-green-200 text-green-700 transition-colors active:scale-95">
                              <i className="fas fa-phone-alt text-sm mb-0.5"></i><span className="text-[9px] font-bold">Gọi</span>
                          </button>
                          <button onClick={handleDetailAction.zalo} className="flex flex-col items-center justify-center p-2 rounded-xl bg-blue-100 hover:bg-blue-200 text-blue-700 transition-colors active:scale-95">
                              <span className="font-black text-sm mb-0.5">Z</span><span className="text-[9px] font-bold">Zalo</span>
                          </button>
                          <button onClick={handleDetailAction.print} className="flex flex-col items-center justify-center p-2 rounded-xl bg-white border border-gray-200 hover:bg-gray-50 text-gray-600 transition-colors active:scale-95">
